+fn handleTmuxQuery(server: *Server, query: []const u8) ?[]const u8 {
+    const allocator = server.allocator;
+
+    // Parse cmd= from query
+    var cmd: []const u8 = "";
+    var format: []const u8 = "";
+    var pane_str: []const u8 = "";
