+    var params = std.mem.splitScalar(u8, query, '&');
+    while (params.next()) |param| {
+        if (std.mem.startsWith(u8, param, "cmd=")) {
+            cmd = param[4..];
+        } else if (std.mem.startsWith(u8, param, "format=")) {
+            format = param[7..];
+        } else if (std.mem.startsWith(u8, param, "pane=")) {
+            pane_str = param[5..];
+        }
+    }
