+    if (std.mem.eql(u8, cmd, "display-message")) {
+        const pane_id = std.fmt.parseInt(u32, pane_str, 10) catch 1;
+        return handleTmuxDisplayMessage(server, pane_id, format, allocator);
+    }
+
+    return null;
